+				if got != nil {
+					t.Fatalf("expected nil, got %+v", *got)
+				}
+				return
+			}
+			if got == nil {
+				t.Fatal("expected status, got nil")
+			}
+			if got.Running != tc.expectLive {
+				t.Errorf("Running = %v, want %v", got.Running, tc.expectLive)
+			}
